<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Checkbox Automation</title>
</head>
<body>

<!-- Example checkboxes -->
<input type="checkbox" id="checkbox1" value="1"> Checkbox 1<br>
<input type="checkbox" id="checkbox2" value="2"> Checkbox 2<br>
<input type="checkbox" id="checkbox3" value="3"> Checkbox 3<br>

<!-- Example Save button -->
<button id="saveButton">Save</button>

<script>
    // Function to check all checkboxes
    function selectAllCheckboxes() {
        // Select all checkboxes
        const checkboxes = document.querySelectorAll('input[type="checkbox"]');

        // Check each checkbox
        checkboxes.forEach(checkbox => {
            checkbox.checked = true;
        });
    }

    // Function to handle the save action
    function saveSelections() {
        // Select all checkboxes
        selectAllCheckboxes();

        // Find the save button and trigger a click event
        const saveButton = document.getElementById('saveButton');
        if (saveButton) {
            saveButton.click();
        }
    }

    // Attach the saveSelections function to an event or directly call it
    // For example, you can attach it to a button click:
    document.getElementById('saveButton').addEventListener('click', saveSelections);

    // Alternatively, you can call the function directly if needed
    // saveSelections();
</script>

</body>
</html>
```

